			return -1;
		}
	}

	if (argc == 0 || argc >= MAX_EXEC_ARGS) {
		kfree(kargv);
		return -1;
	}

	ret = execve_kernel(path, kargv, argc);
	kfree(kargv);
	return ret < 0 ? ret : argc;
}

