void m_trap(uint64 mcause, uint64 mepc, uint64 *regs)
{
	// Check whether the most significant bit is ahn exception or an
	// interrupt
	int is_interrupt = (mcause >> 63) & 1;

	uint64 code = mcause & ((1ULL << 63) - 1);

	// WARNING: Ban kprintf and panic
	// Because the current SP is not in a valid state, the SP has already
	// been saved, and the current SP is in an undefined state.
	if (is_interrupt) {
		// PERF: The code block where 'code == 7' cannot be removed. At
		// the beginning of the 'mstart' function, we set the interrupt
		// enbale bit for 'mie.MTIE', and this code block is the only
		// one capable of handling the MTIP branch. Removing it would
		// cause the OS to hang immediately

		// NOTE: The entire CLINT trigger sequence is initiated via an
		// SBI call, which sets the next response time, clears the STIP
		// suspend bit from the previous cycle, and then waits for the
		// specified duration. Upon time expiration, CLINT generates an
		// MTI interrupt, entering the M-mode handling entry point. It
		// proceeds to the code segment where code == 7, sets the next
		// time to infinity to prevent infinite loops, then sets the
		// STIP bit. It enters the S-mode interrupt handler, responds to
		// cause == 5, and subsequently re-enters the M-mode interrupt
		// function. Here, it uses SBI to set the next response time and
		// clears STIP to avoid infinite loops.

		if (code == 7) {
			uint64 *mtimecmp =
			    (uint64 *) CLINT_MTIMECMP(r_mhartid());
			*mtimecmp = -1ULL; // Set the distance to infinity

			w_mip(r_mip() | MIP_STIP); // Key: Set STIP to allow S
						   // to receive scause = 5
		}
		return;
	} else {
		if (code == 9) {	       // ecall from S
			uint64 eid = regs[16]; // a7
			uint64 fid = regs[15]; // a6
			uint64 arg0 = regs[9]; // a0 = stime_value

			if ((eid == SBI_EID_TIME && fid == SBI_FID_SET_TIMER) ||
			    (eid == SBI_EID_LEGACY_SET_TIMER)) {

				uint64 *mtimecmp =
				    (uint64 *) CLINT_MTIMECMP(r_mhartid());
				*mtimecmp = arg0;

				regs[9] = SBI_SUCCESS; // a0
				regs[10] = 0;	       // a1
			} else {
				regs[9] = -2; // SBI_ERR_NOT_SUPPORTED
				regs[10] = 0;
			}

			w_mip(r_mip() & ~MIP_STIP);

			w_mepc(mepc + 4);
			return;
		} else {

			while (1)
				;
		}
	}
}

#include "asm/machine.h"
#include "asm/riscv.h"
#include "kernel/types.h"
#include "platform/defs.h"

extern void s_mode_start(void);

extern void m_trap_handler(void);

// Register 32 is one of the 32 general-purpose registers in RISC-V architecture
// meaning it is one of the registers we need to save during a savepoint.
uint64 mscratch0[NCPU * 32];

__attribute__((noreturn)) void mstart(void)
{
	// configure PMP. PMP will perform checks when MPP is set to S or U in
	// mstatus. In PMP, the three permission bits R/X/W must be set
	//
	// here we intend to configure addr0 and cfg0, setting their usable
	// range with an upper bound of pmpaddr0 and a lower bound of 0. Below
	// is the original text from the manual: If PMP entry 0’s A field is set
	// to TOR, zero is used for the lower bound, and so it matches any
	// address y<pmpaddr0 end
	w_pmpaddr0(~0ULL);
	w_pmpcfg0(0x0f); // 0x0f = 0000_1111b: A-X-W-R

	// Disable interrupts
	w_satp(0);
	// Force refresh
	sfence_vma();

	int hartid = (int) r_mhartid();
	w_mscratch((uint64) &mscratch0[(int64) hartid * 32]);
	w_mtvec((uint64) m_trap_handler);

	uint64 x = r_mstatus();
	// Set all lower than the two bits of the MPP to 1, then perform the AND
	// operation, Only retain the position that should be 1
	x &= ~MSTATUS_MPP_MASK;
	// Set S mode, but setting it does not switch to S mode immediately
	x |= MSTATUS_MPP_S;

	w_mstatus(x);

	pre_timerinit();

	// NOTE: Interrupt = 1
	w_mideleg((1 << 5) | (1 << 9));
	// NOTE: Interrupt = 0
	// delegate the following exceptions

	w_medeleg((1 << 1) | (1 << 2) | (1 << 3) | (1 << 8) | (1 << 12) |
		  (1 << 13) | (1 << 15));
	// w_medeleg(I_S_INSTRUCTION_ACCESS_FAULT | I_S_ILLEGAL_INSTRUCTION |
	//           I_S_BREAKPOINT  | I_S_ECALL_FROM_USER_MODE |
	//           I_S_INSTRUCTION_PAGE_FAULT | I_S_LOAD_PAGE_FAULT |
	//           I_S_STORE_PAGE_FAULT);

	// keep each CPU's hartid in its tp register, for cpuid().
	int id = (int) r_mhartid();
	w_tp(id);

	// set the starting position of the MEPC
	w_mepc((uint64) s_mode_start);

	// will switch to S-mode and jump to the address in MEPC
	asm volatile("mret");

	__builtin_unreachable();
}

