#include "kernel/bcache.h"
#include "kernel/defs.h"
#include "kernel/fs.h"
#include "kernel/log.h"
#include "kernel/types.h"
#include "easyfs.h"

/*
 * Reference contract:
 * - Entry: caller holds no inode locks.
 * - Exit success: allocates an on-disk inode slot and returns a referenced,
 *   unlocked inode from get_inode().
 * - Failure: releases any buffer locks acquired internally and returns 0.
 * - Ownership: caller must eventually release the returned inode with
 *   put_inode(), or by locking it and then calling iunlockput().
 */
struct vfs_inode *ialloc(uint32 dev)
{
	// inode bitmap
	uint32 ino;

	struct buf *buf = bread(dev, INOBLK_BMIP);
	for (int i = 0; i < BSIZE; i++) {
		// All slots are currently filled
		if (buf->data[i] == 0xFF)
			continue;
		int temp = 1;
		// Find unused bits
		for (int shift = 0; shift < 8; shift++) {
			temp = 1 << shift;
			if (!(buf->data[i] & temp)) {
				// Set this bit to 1
				buf->data[i] |= temp;

				ino = (i * 8) + shift;
				goto handle_found;
			}
		}
		LOG_WARN("ialloc: out of space");
	}
	LOG_WARN("ialloc: No available space");
	brelse(buf);
	return 0;

handle_found:
	bwrite(buf);
	brelse(buf);

	return get_inode(EASYFS_DEV, ino);
}

void ifree(uint32 dev, uint32 ino)
{
	struct buf *buf = bread(dev, INOBLK_BMIP);
	int i = ino / 8;
	int shift = ino % 8;
	buf->data[i] &= ~(1 << shift);
	bwrite(buf);
	brelse(buf);

	uint32 data_block = (ino / 64) + INODE_BLOCK;
	uint32 offset = ino % 64;
	struct buf *data_buf = bread(dev, data_block);
	struct disk_inode *inode =
	    (struct disk_inode *) data_buf->data + offset;
	memset(inode, 0, sizeof(struct disk_inode));
	bwrite(data_buf);
	brelse(data_buf);
}

// xv6
// Copy a modified in-memory inode to disk.
// Must be called after every change to an ip->xxx field
// that lives on disk.
// Caller must hold ip->lock.
/*
 * Lock contract:
 * - Entry: caller must hold ip->lock.
 * - Exit: leaves ip->lock held after copying in-memory inode metadata to the
 *   on-disk inode.
 * - Ownership: does not change the inode reference count.
 */
void iupdate(struct vfs_inode *ip)
{
	struct buf *bp;
	struct disk_inode *dip;
	uint32 blkno;
	uint32 offset;

	blkno = INODE_BLOCK + (ip->ino / 64);
	offset = ip->ino % 64;

	bp = bread(0, blkno);

	dip = (struct disk_inode *) bp->data + offset;
	dip->type = ip->type;
	dip->nlinks = ip->nlinks;
	dip->size = ip->size;
	struct easyfs_inode_info *ei =
	    (struct easyfs_inode_info *) ip->private_data;
	memmove(dip->blocks, ei->blocks, sizeof(ei->blocks));

	bwrite(bp);
	brelse(bp);
}

static int easyfs_vfs_read(struct file *f, uint8 *buffer, uint32 size)
{
	if (f == 0 || f->node == 0 || buffer == 0) {
		return -1;
	}

	vfs_ilock(f->node);
	int n = easyfs_read_inode(f->node, 0, (uint64) buffer, f->offset, size);
	vfs_iunlock(f->node);

	return n;
}

static int easyfs_vfs_write(struct file *f, uint8 *buffer, uint32 size)
{
	if (f == 0 || f->node == 0 || buffer == 0) {
		return -1;
	}

	vfs_ilock(f->node);
	int n =
	    easyfs_write_inode(f->node, 0, (uint64) buffer, f->offset, size);
	vfs_iunlock(f->node);

	return n;
}

static int easyfs_vfs_stat(struct vfs_inode *node, struct stat *st)
{
	if (node == 0 || st == 0)
		return -1;

	st->addr = 0;
	st->type = node->type;
	st->nlink = node->nlinks;
	st->size = node->size;

	return 0;
}

static struct vfs_inode_ops easyfs_inode_ops = {
    .lookup = easyfs_vfs_lookup,
    .stat = easyfs_vfs_stat,
    .create = easyfs_vfs_create,
    .truncate = easyfs_itrunc,
    .unlink = easyfs_vfs_unlink,
    .mkdir = easyfs_vfs_mkdir,
};

static struct vfs_file_ops easyfs_file_ops = {
    .read = easyfs_vfs_read,
    .write = easyfs_vfs_write,
    .readdir = 0,
    .lseek = 0,
    .close = 0,
};

static struct vfs_superblock_ops easyfs_superblock_ops = {
    .alloc_inode = 0,
    .destroy_inode = put_inode,
    .write_super = 0,
};

struct vfs_inode *easyfs_fill_vfs_inode(uint32 ino, struct disk_inode *inode,
					uint8 file_type)
{
	struct vfs_inode *vip = get_inode(EASYFS_DEV, ino);
	if (!vip)
		return 0;

	struct easyfs_inode_info *info = vip->private_data;

	if (!info) {
		kfree(vip);
		LOG_ERROR("easyfs_inode_to_vfs: kalloc error");
		return 0;
	}

	memmove(info->blocks, inode->blocks, sizeof(info->blocks));

	vip->ino = ino;
	vip->count = 1;
	vip->nlinks = inode->nlinks;
	vip->type = file_type;
	vip->size = inode->size;
	vip->ops = &easyfs_inode_ops;
	vip->default_f_ops = &easyfs_file_ops;
	vip->private_data = info;
	vip->sb = easyfs_get_root_sb();
	vip->sb->ops = &easyfs_superblock_ops;

	initsleeplock(&vip->lock, "easyfs inode");

	return vip;
}

int easyfs_vfs_mkdir(struct vfs_inode *dir, char *name, int mode)
{
	if (dir == 0 || name == 0 || name[0] == '\0')
		return -1;
	if (mode != 0) {
		LOG_WARN("easyfs_vfs_mkdir: mode not supported");
		return -1;
	}

	easyfs_ilock(dir);
	struct vfs_inode *existing = easyfs_vfs_lookup(dir, name, 0);
	if (existing != 0) {
		put_inode(existing);
		easyfs_iunlock(dir);
		return -1;
	}
	struct vfs_inode *ip = ialloc(EASYFS_DEV);
	if (ip == 0) {
		easyfs_iunlock(dir);
		return -1;
	}

	easyfs_ilock(ip);
	ip->type = VFS_DIR;
	ip->nlinks = 1;
	iupdate(ip);

	if (dirlink(ip, ".", ip->ino) < 0 || dirlink(ip, "..", dir->ino) < 0 ||
	    dirlink(dir, name, ip->ino) < 0) {
		ip->nlinks = 0;
		iupdate(ip);
		easyfs_iunlockput(ip);
		easyfs_iunlock(dir);
		return -1;
	}

	dir->nlinks++;
	iupdate(dir);

	easyfs_iunlockput(ip);
	easyfs_iunlock(dir);
	return 0;
}

int easyfs_vfs_create(struct vfs_inode *dir, char *path, int mode)
{
	if (dir == 0 || path == 0 || path[0] == '\0')
		return -1;

	easyfs_ilock(dir);
	struct vfs_inode *existing = easyfs_vfs_lookup(dir, path, 0);
	if (existing != 0) {
		put_inode(existing);
		easyfs_iunlock(dir);
		return -1;
	}

	struct vfs_inode *ip = ialloc(EASYFS_DEV);
	if (ip == 0) {
		easyfs_iunlock(dir);
		return -1;
	}

	easyfs_ilock(ip);
	ip->type = mode;
	ip->nlinks = 1;
	iupdate(ip);
	easyfs_iunlock(ip);

	if (dirlink(dir, path, ip->ino) < 0) {
		easyfs_ilock(ip);
		ip->nlinks = 0;
		iupdate(ip);
		easyfs_iunlockput(ip);
		easyfs_iunlock(dir);
		return -1;
	}

	put_inode(ip);
	easyfs_iunlock(dir);
	return 0;
}

int easyfs_vfs_unlink(struct vfs_inode *dir, char *name)
{
	struct vfs_inode *ip;
	struct disk_dir_entry de;
	uint32 off;

	if (dir == 0 || name == 0 || name[0] == '\0') {
		return -1;
	}

	easyfs_ilock(dir);

	// cannot unlink "." or ".."
	if (namecmp(name, ".") == 0 || namecmp(name, "..") == 0)
		goto fail;

	if ((ip = easyfs_vfs_lookup(dir, name, &off)) == 0) {
		goto fail;
	}

	easyfs_ilock(ip);
	if (ip->nlinks < 1)
		panic("unlink: nlink < 1");

	if (ip->type == VFS_DIR) {
		easyfs_iunlockput(ip);
		LOG_WARN("unlink: directory unlink is not supported");
		goto fail;
	}

	memset(&de, 0, sizeof(de));
	if ((easyfs_write_inode(dir, 0, (uint64) &de, off, sizeof(de))) !=
	    sizeof(de)) {
		panic("unlink: writei failed");
	}

	ip->nlinks--;
	if (ip->nlinks == 0) {
		easyfs_itrunc(ip, 0);
		ifree(EASYFS_DEV, ip->ino);
	}
	iupdate(ip);
	easyfs_iunlockput(ip);
	easyfs_iunlock(dir);

	return 0;
fail:
	easyfs_iunlock(dir);
	return -1;
}

#include "kernel/bcache.h"
#include "kernel/types.h"
#include "easyfs.h"
#include "kernel/defs.h"
#include "kernel/log.h"
#include "kernel/fs.h"
/**
 * balloc - Allocate a free data block
 *
 * Context: Search for free bits in the data bitmap on page 3 and allocate the
 * corresponding space in the data area.
 *
 * Lock contract:
 * - Entry: caller holds no buffer locks for the data bitmap or allocated block.
 * - Exit: releases all buffer locks acquired internally.
 * - Success: returns an allocated, zeroed data block number.
 * - Failure: returns 0.
 *
 * Return: Returns the block address of the corresponding data area found
 * */
uint32 balloc(uint32 dev)
{
	struct buf *buf;
	uint32 data_block;

	buf = bread(dev, DABLK_BMIP);
	uint32 max_data_blocks = TOTAL_BLOCKS - DATA_BLOCK;
	for (uint32 bit = 0; bit < max_data_blocks; bit++) {
		uint32 byte_idx = bit / 8;
		uint32 bit_idx = bit % 8;
		// All slots are currently filled
		if (buf->data[byte_idx] == 0xFF)
			continue;

		uint8 mask = 1 << bit_idx;
		if (!(buf->data[byte_idx] & mask)) {
			buf->data[byte_idx] |= mask;
			data_block = bit + DATA_BLOCK;
			goto handle_found;
		}
	}
	LOG_WARN("balloc: No available bits found");
	brelse(buf);
	return 0;

handle_found:
	bwrite(buf);
	brelse(buf);
	struct buf *data_buf = bread(0, data_block);
	memset((void *) data_buf->data, 0, BSIZE);
	bwrite(data_buf);
	brelse(data_buf);
	LOG_TRACE("Allocated block %d", data_block);

	return data_block;
};

/**
 * bfree - Free a data block
 *
 * Context: Mark the corresponding bit in the data bitmap as free and zero out
 * the data area
 *
 * Lock contract:
 * - Entry: caller holds no buffer locks for the data bitmap or target block.
 * - Exit: releases all buffer locks acquired internally.
 * - Ownership: caller must ensure no live inode metadata still references
 *   block_num.
 * */
void bfree(uint32 dev, uint32 block_num)
{
	if (block_num < DATA_BLOCK || block_num >= TOTAL_BLOCKS) {
		panic("bfree: block number out of range");
	}

	uint32 offset = block_num - DATA_BLOCK;
	uint32 byte_idx = offset / 8;
	uint32 bit_idx = offset % 8;

	struct buf *buf = bread(dev, DABLK_BMIP);
	int mask = (1 << bit_idx);

	// A clear bit means the block was already free.
	if (!(buf->data[byte_idx] & mask)) {
		panic("bfree: block already free");
	}

	buf->data[byte_idx] &= ~mask;
	bwrite(buf);
	brelse(buf);
	LOG_TRACE("Freed block %d", block_num);

	// Zero out the freed block for security and easier debugging
	struct buf *data_buf = bread(dev, block_num);
	memset((void *) data_buf->data, 0, BSIZE);
	bwrite(data_buf);
	brelse(data_buf);
	LOG_TRACE("Zeroed out block %d", block_num);
}

/**
 * xv6
 * bmap - Find the disk block content of a file
 *
 * Context: Perform a lookup using the private data stored in the file system
 * specified by `private`
 *
 * @block_num: Logical block number inside the file.
 *
 * Planned indirect-block mapping:
 * - [0, NDIRECT): direct data blocks.
 * - next NINDIRECT blocks: blocks[10] points to one indirect block that stores
 *   data block numbers.
 * - remaining NDINDIRECT blocks: blocks[11] points to a double-indirect block
 *   that stores second-level indirect block numbers; each second-level block
 *   stores data block numbers.
 *
 * Lock contract:
 * - Entry: caller should hold ip->lock to stabilize and, if needed, update
 *   the inode block mapping.
 * - Exit: leaves ip->lock state unchanged.
 * - Side effect: may allocate a new data block and store it in ip private
 *   metadata when the mapping is empty.
 * */
uint bmap(struct vfs_inode *ip, uint32 block_num)
{

	if (block_num < NDIRECT) {
		uint32 addr;
		struct easyfs_inode_info *ei =
		    (struct easyfs_inode_info *) ip->private_data;

		if ((addr = ei->blocks[block_num]) == 0) {
			addr = balloc(EASYFS_DEV);
			if (addr == 0)
				return 0;
			ei->blocks[block_num] = addr;
		}
		return addr;
	} else if (block_num < NDIRECT + NINDIRECT) {
		uint32 idx = block_num - NDIRECT;

		struct easyfs_inode_info *ei =
		    (struct easyfs_inode_info *) ip->private_data;

		uint32 indirect_addr = ei->blocks[SINDIRECT_INDEX];
		if (indirect_addr == 0) {
			indirect_addr = balloc(EASYFS_DEV);
			if (indirect_addr == 0)
				return 0;
			ei->blocks[SINDIRECT_INDEX] = indirect_addr;
		}

		struct buf *indirect = bread(EASYFS_DEV, indirect_addr);
		uint32 *addrs = (uint32 *) indirect->data;

		uint32 addr = addrs[idx];
		if (addr == 0) {
			addr = balloc(EASYFS_DEV);
			if (addr == 0) {
				brelse(indirect);
				return 0;
			}
			addrs[idx] = addr;
			bwrite(indirect);
		}

		brelse(indirect);
		return addr;
	} else if (block_num < NDIRECT + NINDIRECT + NDINDIRECT) {
		uint32 idx = block_num - NDIRECT - NINDIRECT;

		struct easyfs_inode_info *ei =
		    (struct easyfs_inode_info *) ip->private_data;
		uint32 double_indirect = ei->blocks[DINDIRECT_INDEX];

		if (double_indirect == 0) {
			double_indirect = balloc(EASYFS_DEV);
			if (double_indirect == 0) {
				return 0;
			}
			ei->blocks[DINDIRECT_INDEX] = double_indirect;
		}

		struct buf *double_indirect_buf =
		    bread(EASYFS_DEV, double_indirect);

		uint32 *addrs = (uint32 *) double_indirect_buf->data;

		uint32 double_indirect_offset = idx / NINDIRECT;
		uint32 double_indirect_idx = idx % NINDIRECT;

		if (addrs[double_indirect_offset] == 0) {
			addrs[double_indirect_offset] = balloc(EASYFS_DEV);
			if (addrs[double_indirect_offset] == 0) {
				brelse(double_indirect_buf);
				return 0;
			}
			bwrite(double_indirect_buf);
		}

		uint32 indirect_addr = addrs[double_indirect_offset];
		struct buf *indirect_buf = bread(EASYFS_DEV, indirect_addr);
		uint32 *indirect_addrs = (uint32 *) indirect_buf->data;

		if (indirect_addrs[double_indirect_idx] == 0) {
			indirect_addrs[double_indirect_idx] =
			    balloc(EASYFS_DEV);
			if (indirect_addrs[double_indirect_idx] == 0) {
				brelse(indirect_buf);
				brelse(double_indirect_buf);
				return 0;
			}
			bwrite(indirect_buf);
		}

		uint32 addr = indirect_addrs[double_indirect_idx];
		brelse(indirect_buf);
		brelse(double_indirect_buf);
		return addr;
	}

	LOG_WARN("bmap: out of range");
	return 0;
}

#ifndef __EXT4FS_EXT4_H__
#define __EXT4FS_EXT4_H__

#include "kernel/types.h"

/*
 * Minimal read-only EXT4 definitions.
 *
 * Field offsets follow the Linux kernel EXT4 superblock documentation:
 * https://docs.kernel.org/filesystems/ext4/super.html
 */

#define EXT4_SUPER_OFFSET 1024
#define EXT4_SUPER_MAGIC 0xEF53
#define EXT4_ROOT_INO 2

/* Superblock field offsets, relative to EXT4_SUPER_OFFSET.
 *
 * https://docs.kernel.org/filesystems/ext4/super.html
 */
#define EXT4_SB_INODES_COUNT 0x00
#define EXT4_SB_BLOCKS_COUNT_LO 0x04
#define EXT4_SB_FIRST_DATA_BLOCK 0x14
#define EXT4_SB_LOG_BLOCK_SIZE 0x18
#define EXT4_SB_BLOCKS_PER_GROUP 0x20
#define EXT4_SB_INODES_PER_GROUP 0x28
#define EXT4_SB_MAGIC 0x38
#define EXT4_SB_INODE_SIZE 0x58
#define EXT4_SB_FEATURE_COMPAT 0x5c
#define EXT4_SB_FEATURE_INCOMPAT 0x60
#define EXT4_SB_FEATURE_RO_COMPAT 0x64
#define EXT4_SB_DESC_SIZE 0xfe
#define EXT4_SB_BLOCKS_COUNT_HI 0x150

/*
 * Group descriptor field offsets.
 * With 64bit enabled, high 32-bit fields are present after the low fields.
 *
 * https://docs.kernel.org/filesystems/ext4/group_descr.html
 */
#define EXT4_GD_INODE_TABLE_LO 0x08
#define EXT4_GD_INODE_TABLE_HI 0x28

/* Inode field offsets, relative to the start of struct ext4_inode.
 *
 * https://docs.kernel.org/filesystems/ext4/inodes.html
 */
#define EXT4_INODE_MODE 0x00
#define EXT4_INODE_SIZE_LO 0x04
#define EXT4_INODE_BLOCKS_LO 0x1c
#define EXT4_INODE_FLAGS 0x20
#define EXT4_INODE_BLOCK 0x28
#define EXT4_INODE_SIZE_HI 0x6c
#define EXT4_INODE_BLOCK_BYTES 60

#define EXT4_EXT_MAGIC 0xF30A

/* Extent header offsets, relative to inode.i_block.
 *
 * https://docs.kernel.org/filesystems/ext4/ifork.html
 */
#define EXT4_EXT_HEADER_MAGIC 0x00
#define EXT4_EXT_HEADER_ENTRIES 0x02
#define EXT4_EXT_HEADER_MAX 0x04
#define EXT4_EXT_HEADER_DEPTH 0x06
#define EXT4_EXT_HEADER_GENERATION 0x08
#define EXT4_EXT_HEADER_SIZE 12

/* Extent leaf entry offsets, relative to the start of struct ext4_extent.
 *
 * https://docs.kernel.org/filesystems/ext4/ifork.html
 */
#define EXT4_EXTENT_BLOCK 0x00
#define EXT4_EXTENT_LEN 0x04
#define EXT4_EXTENT_START_HI 0x06
#define EXT4_EXTENT_START_LO 0x08
#define EXT4_EXTENT_SIZE 12

/* ext4_dir_entry_2 offsets, relative to one directory entry record. */
#define EXT4_DIRENT_INODE 0x00
#define EXT4_DIRENT_REC_LEN 0x04
#define EXT4_DIRENT_NAME_LEN 0x06
#define EXT4_DIRENT_FILE_TYPE 0x07
#define EXT4_DIRENT_NAME 0x08
#define EXT4_NAME_MAX 255

/* ext4_dir_entry_2 file_type values. */
#define EXT4_FT_REG_FILE 1
#define EXT4_FT_DIR 2

/* Feature set: compatible features may be ignored by old implementations. */
#define EXT4_FEATURE_COMPAT_DIR_PREALLOC 0x0001
#define EXT4_FEATURE_COMPAT_IMAGIC_INODES 0x0002
#define EXT4_FEATURE_COMPAT_HAS_JOURNAL 0x0004
#define EXT4_FEATURE_COMPAT_EXT_ATTR 0x0008
#define EXT4_FEATURE_COMPAT_RESIZE_INODE 0x0010
#define EXT4_FEATURE_COMPAT_DIR_INDEX 0x0020

/* Feature set: unsupported incompatible features must reject mounting. */
#define EXT4_FEATURE_INCOMPAT_FILETYPE 0x0002
#define EXT4_FEATURE_INCOMPAT_EXTENTS 0x0040
#define EXT4_FEATURE_INCOMPAT_64BIT 0x0080
#define EXT4_FEATURE_INCOMPAT_FLEX_BG 0x0200

/* Feature set: unsupported read-only-compatible features reject writes. */
#define EXT4_FEATURE_RO_COMPAT_SPARSE_SUPER 0x0001
#define EXT4_FEATURE_RO_COMPAT_LARGE_FILE 0x0002
#define EXT4_FEATURE_RO_COMPAT_HUGE_FILE 0x0008
#define EXT4_FEATURE_RO_COMPAT_DIR_NLINK 0x0020
#define EXT4_FEATURE_RO_COMPAT_EXTRA_ISIZE 0x0040
#define EXT4_FEATURE_RO_COMPAT_METADATA_CSUM 0x0400

struct ext4_fs {
	/* Kernel virtio block device number that contains this EXT4 image. */
	uint32 dev;
	/* EXT4 filesystem block size in bytes, decoded from s_log_block_size.
	 */
	uint32 block_size;
	/* Total filesystem blocks, not bytes. Uses low+high superblock fields.
	 */
	uint64 blocks_count;
	/* Total inode count in the filesystem. */
	uint32 inodes_count;
	/* Number of filesystem blocks in each block group. */
	uint32 blocks_per_group;
	/* Number of inodes in each block group. Used to locate an inode. */
	uint32 inodes_per_group;
	/* On-disk inode size in bytes. This image uses 256-byte inodes. */
	uint16 inode_size;
	/* On-disk group descriptor size in bytes. 64bit images use larger
	 * descs. */
	uint16 desc_size;
	/* Filesystem block number where the group descriptor table starts. */
	uint64 group_desc_block;
	/* Compatible feature bits from the superblock. */
	uint32 feature_compat;
	/* Incompatible feature bits; unknown bits must reject the image. */
	uint32 feature_incompat;
	/* Read-only compatible feature bits; unknown bits reject this reader.
	 */
	uint32 feature_ro_compat;
};

/* Minimal inode snapshot used during reader bring-up. */
struct ext4_inode {
	/* i_mode: file type bits plus permission bits, e.g. 0x41ed for a dir.
	 */
	uint16 mode;
	/* i_size: file length in bytes, assembled from i_size_lo/i_size_high.
	 */
	uint64 size;
	/* i_blocks_lo: number of 512-byte sectors reserved for this inode. */
	uint32 blocks_lo;
	/* i_flags: inode flags. EXT4_EXTENTS_FL means i_block stores extents.
	 */
	uint32 flags;
	/*
	 * Copy of the on-disk inode.i_block[60] byte array.
	 *
	 * https://docs.kernel.org/filesystems/ext4/ifork.html
	 *
	 * This is not a filesystem block number. Its meaning depends on inode
	 * format:
	 * - with EXT4_EXTENTS_FL: starts with ext4_extent_header, then extent
	 *   entries or index entries;
	 * - without EXT4_EXTENTS_FL: contains direct/indirect block pointers.
	 */
	uint8 block[EXT4_INODE_BLOCK_BYTES];
};

/* Header stored at the start of inode.i_block when EXT4_EXTENTS_FL is set. */
struct ext4_extent_header {
	/* eh_magic: must be 0xf30a for an EXT4 extent tree node. */
	uint16 magic;
	/* eh_entries: number of valid entries following this header. */
	uint16 entries;
	/* eh_max: maximum entry capacity of this node, not valid entry count.
	 */
	uint16 max;
	/* eh_depth: 0 means leaf extents; >0 means index nodes. */
	uint16 depth;
	/* eh_generation: tree generation, unused by the current read-only path.
	 */
	uint32 generation;
};

/* One depth-0 extent entry mapping logical file blocks to physical blocks. */
struct ext4_extent {
	/*
	 * ee_block: first logical block inside the file covered by this extent.
	 * This is not a physical disk block number.
	 */
	uint32 block;
	/* ee_len: number of consecutive filesystem blocks in this extent. */
	uint16 len;
	/*
	 * ee_start_hi/ee_start_lo combined: first physical filesystem block on
	 * disk. This is the block number passed to bread() after conversion to
	 * the kernel buffer-cache block size.
	 */
	uint64 start;
};

// private data
struct ext4_inode_info {
	struct ext4_inode disk_inode;
};

