static struct ext4_fs ext4_root_fs;
static int ext4_root_mounted;
extern struct vfs_inode *vfs_root;
static struct super_block sb = {0};

// This reader is intentionally read-only and small. Unknown incompatible
// features are rejected before later code interprets unsupported disk layouts.
static int ext4_check_features(struct ext4_fs *fs)
{
	uint32 supported_incompat =
	    EXT4_FEATURE_INCOMPAT_FILETYPE | EXT4_FEATURE_INCOMPAT_EXTENTS |
	    EXT4_FEATURE_INCOMPAT_64BIT | EXT4_FEATURE_INCOMPAT_FLEX_BG;
	uint32 supported_ro_compat = EXT4_FEATURE_RO_COMPAT_SPARSE_SUPER |
				     EXT4_FEATURE_RO_COMPAT_LARGE_FILE |
				     EXT4_FEATURE_RO_COMPAT_HUGE_FILE |
				     EXT4_FEATURE_RO_COMPAT_DIR_NLINK |
				     EXT4_FEATURE_RO_COMPAT_EXTRA_ISIZE |
				     EXT4_FEATURE_RO_COMPAT_METADATA_CSUM;
	uint32 unknown_incompat = fs->feature_incompat & ~supported_incompat;
	uint32 unknown_ro_compat = fs->feature_ro_compat & ~supported_ro_compat;

	if (unknown_incompat != 0) {
		LOG_ERROR("ext4: unsupported incompat features: %x",
			  unknown_incompat);
		return -1;
	}

	if (unknown_ro_compat != 0) {
		LOG_ERROR("ext4: unsupported ro_compat features: %x",
			  unknown_ro_compat);
		return -1;
	}

	if ((fs->feature_incompat & EXT4_FEATURE_INCOMPAT_EXTENTS) == 0) {
		LOG_ERROR("ext4: non-extent inode data is not supported");
		return -1;
	}

	return 0;
}

// Read just enough of the superblock to drive the minimal read-only path:
// block sizing, inode table location parameters, and feature gates.
int ext4_mount(uint32 dev, struct ext4_fs *fs)
{
	struct buf *b = bread(dev, 0);
	const uint8 *sb = b->data + EXT4_SUPER_OFFSET;
	uint16 magic = ext4_read_le16(sb + EXT4_SB_MAGIC);

	if (magic != EXT4_SUPER_MAGIC) {
		LOG_TRACE("ext4: dev %d has no ext4 superblock", dev);
		brelse(b);
		return -1;
	}

	uint32 log_block_size = ext4_read_le32(sb + EXT4_SB_LOG_BLOCK_SIZE);
	uint32 blocks_lo = ext4_read_le32(sb + EXT4_SB_BLOCKS_COUNT_LO);
	uint32 blocks_hi = ext4_read_le32(sb + EXT4_SB_BLOCKS_COUNT_HI);

	fs->dev = dev;
	fs->block_size = 1024U << log_block_size;
	fs->blocks_count = ((uint64) blocks_hi << 32) | blocks_lo;
	fs->inodes_count = ext4_read_le32(sb + EXT4_SB_INODES_COUNT);
	fs->blocks_per_group = ext4_read_le32(sb + EXT4_SB_BLOCKS_PER_GROUP);
	fs->inodes_per_group = ext4_read_le32(sb + EXT4_SB_INODES_PER_GROUP);
	fs->inode_size = ext4_read_le16(sb + EXT4_SB_INODE_SIZE);
	fs->desc_size = ext4_read_le16(sb + EXT4_SB_DESC_SIZE);
	// For 1 KiB block filesystems, block 0 is before the superblock and the
	// GDT starts at block 2. For larger block sizes, the GDT starts at
	// block 1.
	fs->group_desc_block = fs->block_size == 1024 ? 2 : 1;
	fs->feature_compat = ext4_read_le32(sb + EXT4_SB_FEATURE_COMPAT);
	fs->feature_incompat = ext4_read_le32(sb + EXT4_SB_FEATURE_INCOMPAT);
	fs->feature_ro_compat = ext4_read_le32(sb + EXT4_SB_FEATURE_RO_COMPAT);

	brelse(b);
	return ext4_check_features(fs);
}

// Mount the boot root EXT4 image and keep its decoded superblock state alive.
//
// The probe path can use a stack ext4_fs, but VFS lookup/read code needs this
// state to outlive the caller that performed the mount.
int ext4_mount_root(uint32 dev)
{
	if (ext4_mount(dev, &ext4_root_fs) < 0) {
		ext4_root_mounted = 0;
		return -1;
	}

	ext4_root_mounted = 1;
	vfs_root = ext4_namei("/");
	struct ext4_fs *fs = ext4_get_root_fs();
	sb.root = vfs_root;
	sb.magic = EXT4_SB_MAGIC;
	sb.block_size = fs->block_size;
	sb.dev = fs->dev;
	sb.private_data = &ext4_root_fs;

	return 0;
}

// Return the mounted root EXT4 context, or 0 before ext4_mount_root succeeds.
//
// This lets future VFS code fail cleanly instead of reading through an
// uninitialized mount context.
struct ext4_fs *ext4_get_root_fs(void)
{
	if (!ext4_root_mounted) {
		return 0;
	}

	return &ext4_root_fs;
}

struct super_block *ext4_get_root_sb(void)
{
	if (!ext4_root_mounted) {
		return 0;
	}

	return &sb;
}

#include "ext4.h"
#include "core/proc.h"
#include "kernel/defs.h"
#include "kernel/fs.h"
#include "kernel/log.h"

static struct vfs_inode *ext4_inode_to_vfs(uint32 ino, struct ext4_inode *inode,
					   uint8 file_type);

static int ext4_vfs_read(struct file *f, uint8 *buffer, uint32 size)
{
	struct ext4_fs *fs = ext4_get_root_fs();
	struct ext4_inode_info *info;

	if (fs == 0 || f == 0 || f->node == 0) {
		return -1;
	}

	info = (struct ext4_inode_info *) f->node->private_data;
	if (info == 0) {
		return -1;
	}

	return ext4_read_file(fs, &info->disk_inode, f->offset, buffer, size);
}

static int ext4_vfs_stat(struct vfs_inode *node, struct stat *st)
{
	if (node == 0 || st == 0) {
		return -1;
	}

	st->addr = 0;
	st->type = node->type == VFS_DIR ? T_DIR : T_FILE;
	st->nlink = node->nlinks;
	st->size = node->size;
	return 0;
}

struct vfs_inode *ext4_vfs_lookup(struct vfs_inode *dir, char *name,
				  uint32 *offset)
{
	struct ext4_fs *fs;
	if ((fs = ext4_get_root_fs()) == 0) {
		LOG_ERROR("ext4_vfs_lookup: ext4_get_root_fs error");
		return 0;
	}

	if (dir == 0 || dir->type != VFS_DIR || dir->private_data == 0) {
		return 0;
	}

	struct ext4_inode_info *dir_info =
	    (struct ext4_inode_info *) dir->private_data;
	struct ext4_inode inode;
	uint8 file_type;
	uint32 ino;

	if (offset != 0) {
		*offset = 0;
	}

	if (ext4_lookup_in_dir(fs, &dir_info->disk_inode, name, &ino,
			       &file_type) < 0) {
		return 0;
	}

	if (ext4_read_inode(fs, ino, &inode) < 0) {
		return 0;
	}

	return ext4_inode_to_vfs(ino, &inode, file_type);
}

static struct vfs_inode_ops ext4_inode_ops = {
    .lookup = ext4_vfs_lookup,
    .stat = ext4_vfs_stat,
};

static struct vfs_file_ops ext4_file_ops = {
    .read = ext4_vfs_read,
    .write = 0,
    .readdir = 0,
    .lseek = 0,
    .close = 0,
};

static struct vfs_superblock_ops ext4_sb_ops = {
    .alloc_inode = 0,
    .destroy_inode = put_inode,
    .write_super = 0,
};

static struct vfs_inode *ext4_inode_to_vfs(uint32 ino, struct ext4_inode *inode,
					   uint8 file_type)
{
	short type;
	if (file_type == EXT4_FT_DIR) {
		type = VFS_DIR;
	} else if (file_type == EXT4_FT_REG_FILE) {
		type = VFS_FILE;
	} else {
		return 0;
	}

	struct ext4_fs *fs = ext4_get_root_fs();
	struct vfs_inode *vip = get_inode(fs->dev, ino);
	if (!vip)
		return 0;

	struct ext4_inode_info *info =
	    (struct ext4_inode_info *) vip->private_data;
	if (!info) {
		return 0;
	}

	info->disk_inode = *inode;

	vip->ino = ino;
	vip->count = 1;
	vip->nlinks = 1; // guard
	vip->type = type;
	vip->size = inode->size;
	vip->ops = &ext4_inode_ops;
	vip->default_f_ops = &ext4_file_ops;
	vip->private_data = info;

	vip->sb = ext4_get_root_sb();
	vip->sb->ops = &ext4_sb_ops;

	initsleeplock(&vip->lock, "ext4 inode");

	return vip;
}

/* ext4_namei - Look up and return the inode for a path name */
struct vfs_inode *ext4_namei(char *path)
{
	struct ext4_fs *fs;
	if ((fs = ext4_get_root_fs()) == 0) {
		LOG_ERROR("ext4_namei: ext4_get_root_fs error");
		return 0;
	}

	struct ext4_inode inode;
	uint8 file_type;
	uint32 ino;

	if (ext4_lookup_path_ino(fs, path, &inode, &file_type, &ino) < 0) {
		LOG_ERROR("ext4_namei: ext4_lookup_path_ino error");
		return 0;
	}

	return ext4_inode_to_vfs(ino, &inode, file_type);
}

