static int ext4_lookup_in_dir_block(struct ext4_fs *fs, uint64 block,
				    const char *name, uint32 *ino,
				    uint8 *file_type)
{
	uint64 byte_offset = block * fs->block_size;
	uint64 cache_block = byte_offset / BSIZE;
	uint64 offset_in_cache = byte_offset % BSIZE;
	struct buf *b = bread(fs->dev, cache_block);
	uint64 offset = 0;

	while (offset < fs->block_size) {
		const uint8 *dirent = b->data + offset_in_cache + offset;
		uint32 entry_ino = ext4_read_le32(dirent + EXT4_DIRENT_INODE);
		uint16 rec_len = ext4_read_le16(dirent + EXT4_DIRENT_REC_LEN);
		uint8 name_len = *(dirent + EXT4_DIRENT_NAME_LEN);
		uint8 entry_type = *(dirent + EXT4_DIRENT_FILE_TYPE);

		if (rec_len < EXT4_DIRENT_NAME ||
		    offset + rec_len > fs->block_size) {
			brelse(b);
			return -1;
		}

		if (entry_ino != 0 && name_len <= EXT4_NAME_MAX &&
		    EXT4_DIRENT_NAME + name_len <= rec_len &&
		    ext4_name_eq(dirent + EXT4_DIRENT_NAME, name_len, name)) {
			*ino = entry_ino;
			*file_type = entry_type;
			brelse(b);
			return 0;
		}

		offset += rec_len;
	}

	brelse(b);
	return -1;
}

int ext4_lookup_in_dir(struct ext4_fs *fs, struct ext4_inode *dir,
		       const char *name, uint32 *ino, uint8 *file_type)
{
	struct ext4_extent_header eh;

	if (ext4_read_extent_header(dir, &eh) < 0) {
		return -1;
	}

	if (eh.depth != 0) {
		LOG_ERROR("ext4: indexed extent lookup is not supported");
		return -1;
	}

	for (uint16 i = 0; i < eh.entries; i++) {
		struct ext4_extent ex;
		ext4_read_extent(dir, i, &ex);

		for (uint16 j = 0; j < ex.len; j++) {
			if (ext4_lookup_in_dir_block(fs, ex.start + j, name,
						     ino, file_type) == 0) {
				return 0;
			}
		}
	}

	return -1;
}

// Resolve an absolute path from the EXT4 root directory.
//
// On success, returns the final inode snapshot, its ext4_dir_entry_2 file_type,
// and optionally the final inode number. The inode number is needed when the
// result is wrapped as a vfs_inode and cached by identity.
int ext4_lookup_path_ino(struct ext4_fs *fs, const char *path,
			 struct ext4_inode *inode, uint8 *file_type,
			 uint32 *ino)
{
	if (*path != '/')
		return -1;
	struct ext4_inode root;
	if (ext4_read_inode(fs, EXT4_ROOT_INO, &root) != 0)
		return -1;

	char name[PATH_MAX];
	struct ext4_inode cur = root;
	uint8 cur_type = EXT4_FT_DIR;
	uint32 cur_ino = EXT4_ROOT_INO;

	while ((path = skipelem((char *) path, name)) != 0) {
		uint32 next_ino;
		uint8 next_type;

		if (cur_type != EXT4_FT_DIR)
			return -1;
		if (ext4_lookup_in_dir(fs, &cur, name, &next_ino, &next_type) !=
		    0)
			return -1;
		if (ext4_read_inode(fs, next_ino, &cur) != 0)
			return -1;

		cur_ino = next_ino;
		cur_type = next_type;
	}

	*inode = cur;
	*file_type = cur_type;
	if (ino != 0) {
		*ino = cur_ino;
	}
	return 0;
}

// Compatibility wrapper for callers that only need the inode contents and type.
int ext4_lookup_path(struct ext4_fs *fs, const char *path,
		     struct ext4_inode *inode, uint8 *file_type)
{
	return ext4_lookup_path_ino(fs, path, inode, file_type, 0);
}

#include "kernel/bcache.h"
#include "kernel/defs.h"
#include "kernel/log.h"
#include "kernel/types.h"

#define LOG_MODULE "BLCK"

struct bcache bcache;

// xv6
/**
 * binit - initialize the buffer cache
 *
 * Context: Initialize the block cache
 * */
void binit(void)
{
	struct buf *b;

	initlock(&bcache.bcache_lock, "bcache");

	// Create linked list of buffers
	bcache.head.prev = &bcache.head;
	bcache.head.next = &bcache.head;
	for (b = bcache.buf; b < bcache.buf + NNUM; b++) {
		b->next = bcache.head.next;
		b->prev = &bcache.head;
		b->refcnt = 0;
		b->valid = 0;
		b->dirty = 0;
		initsleeplock(&b->buf_lock, "buffer sleep");
		bcache.head.next->prev = b;
		bcache.head.next = b;
	}
}

/**
 * bget - get a block from the buffer cache
 *
 * Lock contract:
 * - Entry: caller holds no buffer sleeplocks.
 * - During lookup: acquires bcache.bcache_lock while searching or selecting a
 *   cache entry.
 * - Exit success: returns a buffer with b->buf_lock held and refcnt
 *   incremented.
 * - Ownership: caller must eventually release the buffer with brelse().
 * */
struct buf *bget(uint32 dev, uint64 blkno)
{
	struct buf *buffer;

	// Check if the pointer survived until here
	acquire(&bcache.bcache_lock);

	// Check whether this cache block exists in the current buffer
	for (buffer = bcache.head.next; buffer != &bcache.head;
	     buffer = buffer->next) {
		if (buffer->blkno == blkno && buffer->dev == dev) {
			buffer->refcnt++;
			release(&bcache.bcache_lock);
			acquiresleep(&buffer->buf_lock);
			return buffer;
		}
	}

	// Find block with no reference and that do no require updates
	// LRU need start from the tail that is the least recently used
	for (buffer = bcache.head.prev; buffer != &bcache.head;
	     buffer = buffer->prev) {
		if (buffer->refcnt == 0 && buffer->dirty == 0) {
			buffer->blkno = blkno;
			buffer->dev = dev;
			buffer->valid = 0;
			buffer->refcnt++;
			release(&bcache.bcache_lock);
			acquiresleep(&buffer->buf_lock);
			return buffer;
		}
	}
	release(&bcache.bcache_lock);

	// Not found
	return 0;
}

// xv6
// Release a locked buffer.
// Move to the head of the most-recently-used list.
/*
 * Lock contract:
 * - Entry: caller must hold b->buf_lock.
 * - Exit: releases b->buf_lock and drops one buffer reference.
 * - Ownership: caller must not access b after this call unless it obtains
 *   another reference through bget() or bread().
 */
void brelse(struct buf *b)
{
	if (!holdingsleep(&b->buf_lock))
		panic("brelse");

	releasesleep(&b->buf_lock);

	acquire(&bcache.bcache_lock);
	b->refcnt--;
	if (b->refcnt == 0) {
		// no one is waiting for it.
		b->next->prev = b->prev;
		b->prev->next = b->next;
		b->next = bcache.head.next;
		b->prev = &bcache.head;
		bcache.head.next->prev = b;
		bcache.head.next = b;
	}

	release(&bcache.bcache_lock);
}

// xv6
/**
 * bread - Get a block from the buffer cache or read from disk
 *
 * Context: First, check the cache for the data; if it isn't there, read it.
 *
 * Lock contract:
 * - Entry: caller holds no lock for the target buffer.
 * - Exit success: returns a valid buffer with b->buf_lock held.
 * - Ownership: caller must call brelse() when finished with the buffer.
 *
 * Return: a locked buf with the contents of the indicated block.
 * */
struct buf *bread(int dev, uint64 blockno)
{
	struct buf *buffer;

	// Find the block or create a new block
	buffer = bget(dev, blockno);

	// If the block is not valid, read from disk
	if (!buffer->valid) {
		virtio_disk_rw(buffer, 0);
		buffer->valid = 1;
	}

	return buffer;
}

// xv6
// Write b's contents to disk.  Must be locked.
/*
 * Lock contract:
 * - Entry: caller must hold buffer->buf_lock.
 * - Exit: leaves buffer->buf_lock held after submitting the disk write.
 * - Ownership: caller remains responsible for releasing the buffer with
 *   brelse().
 */
void bwrite(struct buf *buffer)
{
	if (!holdingsleep(&buffer->buf_lock))
		panic("bwrite: not locked");
	virtio_disk_rw(buffer, 1);
}

#include "kernel/defs.h"
#include "kernel/fs.h"
#include "kernel/icache.h"
#include "kernel/log.h"

#define LOG_MODULE "ICAC"

struct inode_cache icache;

/**
 * icache_init - initialize the inode cache
 * */
void icache_init(void)
{
	initlock(&icache.lock, "icache lock");

	struct vfs_inode *inc;
	// Create linked list of buffers
	icache.head.prev = &icache.head;
	icache.head.next = &icache.head;
	for (inc = icache.inodes; inc < icache.inodes + NINODES; inc++) {
		inc->next = icache.head.next;
		inc->prev = &icache.head;
		inc->count = 0;
		initsleeplock(&inc->lock, "inode lock");
		icache.head.next->prev = inc;
		icache.head.next = inc;
	}
	LOG_TRACE("icache_init done");
}

/**
 * get_inode - search ino in the inode cache
 *
 * Reference contract:
 * - Entry: caller must not hold the target inode sleeplock.
 * - Exit success: returns an unlocked inode with its reference count
 *   incremented.
 * - Ownership: caller must eventually release the reference with
 *   put_inode(), or by locking it and then calling iunlockput().
 *
 * Return: pointer to the inode
 * */
struct vfs_inode *get_inode(uint32 dev, uint32 ino)
{
	(void) dev;

	struct vfs_inode *ip;
	acquire(&icache.lock);

	// Check if the pointer survived until here
	for (ip = &icache.inodes[0]; ip < &icache.inodes[NINODES]; ip++) {
		// info = (struct easyfs_inode_info *) ip->private_data;
		if (ip->ino == ino && ip->count > 0) {
			ip->count++;
			release(&icache.lock);
			LOG_TRACE("get_inode: hit ino %d", ino);
			return ip;
		}
	}

	LOG_TRACE("get_inode: miss ino %d", ino);
	// LRU need start from the tail
	for (ip = icache.head.prev; ip != &icache.head; ip = ip->prev) {
		if (ip->count == 0) {
			ip->ino = ino;
			ip->count = 1;

			ip->private_data = kalloc();

			release(&icache.lock);
			return ip;
		}
	}

	LOG_ERROR("get_inode: no inodes");

	release(&icache.lock);
	return 0;
}

/**
 * put_inode - put inode into the inode cache
 *
 * Reference contract:
 * - Entry: caller must own one reference to ip.
 * - Entry: caller should not hold ip->lock; use iunlockput() when a locked
 *   inode must be unlocked and released together.
 * - Exit: drops one reference. If this was the last reference and the inode
 *   has no links, the inode may be truncated, cleared, and recycled.
 * - Ownership: caller must not use ip after this call unless it owns another
 *   reference.
 * */
void put_inode(struct vfs_inode *ip)
{
	acquire(&icache.lock);
	if (ip->count == 1 && ip->nlinks == 0) {
		// acquiresleep(&ip->lock);
		ip->count = 0;
		// Move this recently freed inode to the MRU position
		// (head.next)
		ip->prev->next = ip->next;
		ip->next->prev = ip->prev;
		kfree(ip->private_data);
		ip->next = icache.head.next;
		ip->prev = &icache.head;
		icache.head.next->prev = ip;
		icache.head.next = ip;
		release(&icache.lock);

		// FIXME: clean the inode
		//
		// itrunc(ip);
		// ip->type = 0;
		// ip->ino = 0;
		// iupdate(ip);

		// releasesleep(&ip->lock);
		return;
	} else {
		ip->count--;
	}
	release(&icache.lock);
}

