};

struct trapframe {
	uint64 ra;  // 0(sp)
	uint64 sp;  // 8(sp)
	uint64 gp;  // 16(sp)
	uint64 tp;  // 24(sp)
	uint64 t0;  // 32(sp)
	uint64 t1;  // 40(sp)
	uint64 t2;  // 48(sp)
	uint64 s0;  // 56(sp)
	uint64 s1;  // 64(sp)
	uint64 a0;  // 72(sp)
	uint64 a1;  // 80(sp)
	uint64 a2;  // 88(sp)
	uint64 a3;  // 96(sp)
	uint64 a4;  // 104(sp)
	uint64 a5;  // 112(sp)
	uint64 a6;  // 120(sp)
	uint64 a7;  // 128(sp)
	uint64 s2;  // 136(sp)
	uint64 s3;  // 144(sp)
	uint64 s4;  // 152(sp)
	uint64 s5;  // 160(sp)
	uint64 s6;  // 168(sp)
	uint64 s7;  // 176(sp)
	uint64 s8;  // 184(sp)
	uint64 s9;  // 192(sp)
	uint64 s10; // 200(sp)
	uint64 s11; // 208(sp)
	uint64 t3;  // 216(sp)
	uint64 t4;  // 224(sp)
	uint64 t5;  // 232(sp)
	uint64 t6;  // 240(sp)

	uint64 epc;
};

// Per-CPU state.
struct cpu {
	struct Process *proc;	// The process running on this cpu, or null.
	struct context context; // swtch() here to enter scheduler().
	int noff;		// Record nesting depth
	int intena; // Record the interrupt status before the first interrupt is
		    // disabled
};

struct vm_area_struct {
	int used;
	uint64 va_start;
	uint64 va_end;

	uint64 flags;
	uint64 file_offset;
	uint64 vm_page_prot;
	struct vm_operations_struct *vm_ops;

	struct file *file;
	void *vm_private_data; // Pointer to private data
};

struct vm_operations_struct {
	void (*open)(struct vm_area_struct *vma);
	void (*close)(struct vm_area_struct *vma);
};

#define NVMA 16 // Number of virtual memory areas

enum proc_state { UNUSED, USED, RUNNABLE, RUNNING, SLEEPING, ZOMBIE };

struct Process {
	enum proc_state state;
	struct spinlock lock;	    // Lock to protect the process
	void *chan;		    // wakeup channel
	int pid;		    // Process ID
	char name[16];		    // Process name
	struct file *ofile[NOFILE]; // Open files
	char cwd[PATH_MAX];	    // Current working directory
	int exit_code;		    // Exit code

	uint64 kstack;		     // Kernel stack pointer
	struct Process *parent;	     // Parent process
	pagetable_t pagetable;	     // Page table
	struct context *context;     // Kernel context
	struct trapframe *trapframe; // User trap frame

	uint64 size;	    // Size of process memory but remove from the stack
	uint64 heap_bottom; // Low address
	uint64 heap_top;    // High address

	uint64 stack_bottom; // Low address
	uint64
	    stack_top; // Upper boundary in the pagetable, Usually PHYSTOP_LOW
	struct vm_area_struct vm_area[NVMA];
};

