/* linker.ld — RISC-V virt bare metal kernel, entry: _start at 0x80000000 */
OUTPUT_ARCH(riscv)
ENTRY(_start)

BASE_ADDRESS = 0xffffffc080000000;

MEMORY
{
  VIRT (rwx) : ORIGIN = 0xffffffc080000000 , LENGTH = 128M
  PHYSMEM (rwx) : ORIGIN = 0x80000000, LENGTH = 128M
}

SECTIONS
{
  /* QEMU virt DRAM satrt address */
  . = BASE_ADDRESS;


  /* .text.entry（_start） */
  .text :
  {
    . = ALIGN(4);
    *(.text.entry)           /*  _start  */
    *(.text .text.*)
    *(.rodata .rodata.*)
    . = ALIGN(0x1000);

    _divide = .;
  } > VIRT AT> PHYSMEM

  .data :
  {
    . = ALIGN(16);
    _data_start = .;
    *(.sdata .sdata.* .data .data.*)
    _data_end = .;
  }  > VIRT AT> PHYSMEM

  .bss :
  {
    . = ALIGN(16);
    _bss_start = .;
    *(.sbss .sbss.* .bss .bss.* COMMON)
    _bss_end = .;
  } > VIRT AT> PHYSMEM

  . = ALIGN(16);
  _stack_bottom = .;
  . = . + 0x4000;
  _stack_top = .;     /* alloc 16kb stack to kernel */

  . = ALIGN(0x1000);

  /* NOTE: High address mapping will cause address elevation*/
  _kernel_end = .;
}

	// Switch back to the CPU's context
	swtch(p->context, &get_cpu()->context);
	get_cpu()->intena = intena;
}

/**
 * yield - Yield the CPU
 *
 * Context: Will switch back to the CPU's context and return to the scheduler
 */
void yield(void)
{
	struct Process *current_proc = get_proc();

	if (current_proc != 0 && current_proc->state == RUNNING) {
		acquire(&current_proc->lock);
		current_proc->state = RUNNABLE;
		sched();
		release(&current_proc->lock);
	}
}

/**
 * alloc_fd - Allocate a free file descriptor
 * */
int alloc_fd(struct Process *p, struct file *f)
{
	acquire(&p->lock);
	for (int i = 0; i < NOFILE; i++) {
		if (p->ofile[i] == 0) {
			p->ofile[i] = f;
			release(&p->lock);
			return i;
		}
	}
	release(&p->lock);
	return -1;
}

void freeproc(struct Process *p)
{
	acquire(&p->lock);
	p->pid = 0;
	p->name[0] = 0;

	if (p->kstack) {
		kfree((void *) p->kstack);
		p->kstack = 0;
	}

	if (p->pagetable) {
		uvmfree(p->pagetable, p);
		p->pagetable = 0;
	}

	if (p->context) {
		kfree((void *) p->context);
		p->context = 0;
	}
	p->trapframe = 0;
	p->size = 0;
	p->parent = 0;

	p->state = UNUSED;
	release(&p->lock);
}

int fork()
{
	LOG_TRACE("Forking");
	struct Process *np = alloc_process();
	struct Process *p = get_proc();
	if (np == 0) {
		return -1;
	}

	acquire(&np->lock);
	if (uvmcopy(p->pagetable, np->pagetable) < 0) {
		freeproc(np);
		return -1;
	}

	np->heap_top = p->heap_top;
	np->heap_bottom = p->heap_bottom;
	np->stack_top = p->stack_top;
	np->stack_bottom = p->stack_bottom;
	strcpy(np->cwd, p->cwd);

	*(np->trapframe) = *(p->trapframe);
	np->trapframe->a0 = 0;
	np->parent = p;

	// Copy open file descriptors
	for (int i = 0; i < NOFILE; i++) {
		if (p->ofile[i]) {
			np->ofile[i] = filedup(p->ofile[i]);
		}
	}

	for (int i = 0; i < NVMA; i++) {
		if (p->vm_area[i].used == 1) {
			np->vm_area[i] = p->vm_area[i];
			if (p->vm_area[i].file != 0) {
				np->vm_area[i].file =
				    filedup(p->vm_area[i].file);
			}
		}
	}

	np->state = RUNNABLE;
	release(&np->lock);

	LOG_TRACE("Forked process %d", np->pid);

	return np->pid;
}

int exit(int exit_code)
{
	struct Process *current;
	struct Process *p;

	current = get_proc();

	for (int i = 0; i < NOFILE; i++) {
		if (current->ofile[i] != 0) {
			struct file *f = current->ofile[i];
			current->ofile[i] = 0;
			fileclose(f);
		}
	}

	for (int i = 0; i < NPROC; i++) {
		p = &proc[i];
		acquire(&p->lock);
		if (p->parent == current) {
			p->parent = &proc[0];
		}
		release(&p->lock);
	}

	wakeup(current->parent);

	acquire(&current->lock);
	current->state = ZOMBIE;
	current->exit_code = exit_code;
	for (int i = 0; i < NVMA; i++) {
		struct vm_area_struct *vma = &current->vm_area[i];
		if (vma->used == 0)
			continue;

		uint64 len = vma->va_end - vma->va_start;
		kvmunmap(current->pagetable, vma->va_start, len, 1);
		if (vma->file != 0) {
			fileclose(vma->file);
		}
		vma->used = 0;
	}

	LOG_TRACE("Process %d exited", current->pid);

	sched();

	panic("zombie exit: return from swtch");

	return 0;
}

/**
 * wait4 - wait for a matching child process to exit
 *
 * pid: -1 waits for any child, otherwise waits for the child with this pid
 * wstatus: user-space address to store the encoded exit status, or 0 to ignore
 * options: 0 waits until exit, WNOHANG returns immediately if no child exited
 *
 * Return: child pid on success, 0 for WNOHANG with a live matching child,
 *         -1 if no matching child exists or status copyout fails
 */
uint64 wait4(int pid, uint64 wstatus, int options)
{
	struct Process *cur = get_proc();
	int have_match;
	int child_pid;

	acquire(&cur->lock); // Hold the parent process lock to prevent missing
			     // the wakeup call when the child process exits

	for (;;) {
		have_match = 0;
		for (int i = 0; i < NPROC; i++) {
			struct Process *p = &proc[i];

			// If it were me, I'd just skip this step, since we
			// already hold cur->lock
			if (p == cur)
				continue;

			acquire(&p->lock);
			if (p->parent == cur && (pid == -1 || p->pid == pid)) {
				// A matching child exists even if it has not
				// exited yet. Otherwise waitpid(pid, ..., 0)
				// would report no child instead of sleeping
				// until the child becomes ZOMBIE.
				have_match = 1;
				if (p->state == ZOMBIE) {
					child_pid = p->pid;
					if (wstatus != 0) {
						int status =
						    (p->exit_code & 0xff) << 8;
						if (copyout(cur->pagetable,
							    (char *) wstatus,
							    (uint64) &status,
							    sizeof(status)) <
						    0) {
							release(&p->lock);
							release(&cur->lock);
							return -1;
						}
					}
					release(&p->lock);
					release(&cur->lock);

					freeproc(p);
					return child_pid;
				}
			}
			release(&p->lock);
		}

		if (have_match == 0) {
			release(&cur->lock);
			return -1;
		}

		if (options & WNOHANG) {
			release(&cur->lock);
			return 0;
		}

		// If you enter `sleep` while holding `cur->lock`, `sleep` will
		// release it internally and enter the scheduler.
		sleep(cur, &cur->lock);
	}
}

uint64 brk(uint64 addr)
{
	struct Process *cur = get_proc();
	uint64 old_head_top = cur->heap_top;
	uint64 new_head_top = addr;

	LOG_TRACE("brk: old_head_top %p, new_head_top %p",
		  (void *) old_head_top, (void *) addr);

	if (addr == 0) {
		return old_head_top;
	}

	if (addr < cur->heap_bottom || addr >= cur->stack_bottom) {
		return old_head_top;
	}

	if (addr >= cur->heap_bottom && addr < cur->heap_top) {
		acquire(&cur->lock);
		uvmdealloc(cur->pagetable, addr, old_head_top - addr);
		release(&cur->lock);
	}

	acquire(&cur->lock);
	cur->heap_top = addr;
	new_head_top = addr;
	release(&cur->lock);

	LOG_TRACE("brk: success");

	return new_head_top;
}

