#include "kernel/types.h"
#include "platform/defs.h"
#include "platform/uart.h"
#include "platform/virtio_mmio.h"

void plic_init_uart(void)
{
	int id = cpuid();
	int context = (2 * id) + 1; // S-mode context

	// Set priority
	plic_set_priority(UART_IRQ, 1);
	plic_set_priority(VIRTIO_IRQ, 2);

	// Set interrupt
	plic_enable_interrupt(context, UART_IRQ);
	plic_enable_interrupt(context, VIRTIO_IRQ);

	plic_set_threshold(context, 0);
}

void plic_set_priority(int id, int priority)
{
	*reg32(PLIC_IP_ADR(id)) = (uint32) priority;
}

int plic_enable_interrupt(int context, int id)
{
	uint32 word = (uint32) id / 32;
	uint32 bit = (uint32) id % 32;
	volatile uint32 *enable = reg32(PLIC_IE_ADR(context, word));
	*enable |= (1U << bit);
	return 0;
}

int plic_set_threshold(int context, int threshold)
{
	*reg32(PLIC_THRESHOLD_ADR(context)) = (uint32) threshold;
	return 0;
}

int plic_claim_interrupt(int context)
{
	return (int) (*reg32(PLIC_CLAIM_ADR(context)));
}

int plic_complete_interrupt(int context, int id)
{
	*reg32(PLIC_IC_ADR(context)) = (uint32) id;
	return 0;
}

#include "asm/mm.h"
#include "platform/sbi.h"
#include "kernel/types.h"
#include "platform/defs.h"

#define QEMU_TEST_BASE 0x100000UL
#define QEMU_TEST_SHUTDOWN 0x5555

// kernel/sbi.c
static inline long sbi_ecall(long eid, long fid, long a0, long a1, long a2,
			     long a3, long a4, long a5, long *out_val)
{
	register long _a0 asm("a0") = a0;
	register long _a1 asm("a1") = a1;
	register long _a2 asm("a2") = a2;
	register long _a3 asm("a3") = a3;
	register long _a4 asm("a4") = a4;
	register long _a5 asm("a5") = a5;
	register long _a6 asm("a6") = fid;
	register long _a7 asm("a7") = eid;
	asm volatile("ecall"
		     : "+r"(_a0), "+r"(_a1)
		     : "r"(_a2), "r"(_a3), "r"(_a4), "r"(_a5), "r"(_a6),
		       "r"(_a7)
		     : "memory");
	if (out_val)
		*out_val = _a1;
	return _a0; // error
}

void sbi_set_timer(uint64 stime_value)
{
	sbi_ecall(SBI_EID_TIME, SBI_FID_SET_TIMER, stime_value, 0, 0, 0, 0, 0,
		  0);
}

void sbi_shutdown(void)
{
	sbi_ecall(SBI_EID_SRST, SBI_FID_SYSTEM_RESET, SBI_RESET_TYPE_SHUTDOWN,
		  SBI_RESET_REASON_NONE, 0, 0, 0, 0, 0);

	// OpenSBI handles SRST under `-bios default`; local `-bios none`
	// development falls back to QEMU virt's sifive,test poweroff device.
	*(volatile uint32 *) PA2VA(QEMU_TEST_BASE) = QEMU_TEST_SHUTDOWN;
	while (1) {
		asm volatile("wfi");
	}
}

